const ManageGames = () => {
  return (
    <div className="p-6 text-white">
      <h2 className="text-3xl font-bold mb-4">Manage Games</h2>
      {/* Game management functionality goes here */}
      <p className="text-gray-400">Add, edit, or remove games displayed on the main site.</p>
    </div>
  );
};

export default ManageGames;
